import React, { useEffect, useState } from "react";
import { getSupabase } from "../../database/supabase";

type Submission = {
  id: string;
  form_id: string;
  data: {
    message?: string;
    [key: string]: any;
  };
  created_at: string;
};

const FORM_ID = "test_form";

const FormAccessPage = () => {
  const [input, setInput] = useState("");
  const [submissions, setSubmissions] = useState<Submission[]>([]);
  const [selected, setSelected] = useState<Submission | null>(null);
  const [loading, setLoading] = useState(false);

  // 🔹 Fetch submissions (only for this form)
  const fetchSubmissions = async () => {
    const supabase = await getSupabase();

    const { data, error } = await supabase
      .from("form_submissions")
      .select("*")
      .eq("form_id", FORM_ID)
      .order("created_at", { ascending: false });

    if (error) {
      console.error("Fetch error:", error);
      return;
    }

    setSubmissions(data || []);
  };

  useEffect(() => {
    fetchSubmissions();
  }, []);

  const handleSave = async () => {
  console.log("CLICKED SAVE");

  if (!input.trim()) {
    console.log("EMPTY INPUT");
    return;
  }

  setLoading(true);

  try {
    const supabase = await getSupabase();
    console.log("SUPABASE READY");

    const payload = {
      form_id: "test_form",
      data: { message: input },
    };

    console.log("INSERT PAYLOAD:", payload);

    const { data, error } = await supabase
      .from("form_submissions")
      .insert([payload])
      .select();

    console.log("INSERT RESULT:", { data, error });

    if (error) {
      console.error("INSERT ERROR:", error);
      return;
    }

    setInput("");
    fetchSubmissions();
  } catch (err) {
    console.error("CRASH:", err);
  } finally {
    setLoading(false);
  }
};

  return (
    <div style={{ padding: "20px", maxWidth: "600px", margin: "0 auto" }}>
      <h2>Test Form</h2>

      {/* 🔹 Input */}
      <div style={{ display: "flex", gap: "10px", marginBottom: "20px" }}>
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Enter message..."
          style={{ flex: 1, padding: "10px" }}
        />
        <button onClick={handleSave} disabled={loading}>
          {loading ? "Saving..." : "Save"}
        </button>
      </div>

      <hr />

      {/* 🔹 List */}
      <h3>All Submissions</h3>
      <div style={{ display: "flex", flexDirection: "column", gap: "8px" }}>
        {submissions.map((item) => (
          <div
            key={item.id}
            onClick={() => setSelected(item)}
            style={{
              padding: "10px",
              border: "1px solid #ccc",
              cursor: "pointer",
              background:
                selected?.id === item.id ? "#eef" : "transparent",
            }}
          >
            {item.data?.message || "(no message)"}
          </div>
        ))}
      </div>

      <hr />

      {/* 🔹 Selected */}
      <h3>Selected Submission</h3>
      {selected ? (
        <div
          style={{
            padding: "15px",
            border: "1px solid #000",
            marginTop: "10px",
          }}
        >
          <p><strong>ID:</strong> {selected.id}</p>
          <p><strong>Form:</strong> {selected.form_id}</p>
          <p><strong>Message:</strong> {selected.data?.message}</p>
          <p><strong>Created:</strong> {selected.created_at}</p>

          <hr />
          <strong>Raw JSON:</strong>
          <pre style={{ whiteSpace: "pre-wrap" }}>
            {JSON.stringify(selected.data, null, 2)}
          </pre>
        </div>
      ) : (
        <p>No submission selected</p>
      )}
    </div>
  );
};

export default FormAccessPage;